import { Box, Button, Container, Dialog, DialogActions, DialogContent, DialogTitle, Grid, Typography, useMediaQuery } from "@mui/material";
import { useTheme } from '@mui/material/styles';
import { navigate } from "gatsby";
import React, { useEffect, useState } from "react";
import ButtonInput from "../../components/ButtonInput/ButtonInput";
import ColorBullets from "../../components/ColorBullets/ColorBullets";
import CustomButton from "../../components/CustomButton/CustomButton";
import Layout from "../../components/Layout";
import SelectSize from "../../components/SelectSize/SelectSize";
import useSettings from "../../storage/useSettings";
import { formatCep, formatMoney } from "../../utils/utils";
import useCart from "../../storage/useCart";
import { IDetailedProduct, IItem } from "../../types/types";
import useAddress from "../../storage/useAddress";
import api, { URL_BACK } from "../../components/api";

export default function Product(props: any) {
    const theme = useTheme();
    const { stocks } = useSettings();
    const { addItemToCart } = useCart();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));
    const productNameId = props.params.name;
    const [colorId, setColorId] = useState<number | undefined>();
    const [sizeId, setSizeId] = useState<number | undefined>();
    const { cacheAddress } = useAddress();
    const initialCep = (cacheAddress && cacheAddress.cep) ? formatCep(cacheAddress.cep) : '';
    const [cep, setCep] = useState<string>(initialCep);
    const [product, setProduct] = useState<IDetailedProduct>();
    const [curPictureId, setCurPictureId] = useState<string | undefined>();

    const [openAlert, setOpenAlert] = useState<boolean>(false);

    const handleBuy = () => {
        console.log(colorId, sizeId)
        if (product && colorId && sizeId) {
            const stock = stocks.find((s) => s.colorId === colorId && s.sizeId === sizeId);
            if (stock) {
                const itemCart: IItem = {
                    productId: product.id, // TODO
                    stockId: stock.id,
                    colorId: colorId,
                    sizeId: sizeId,
                    quantity: 1,
                    name: product.name,
                    unitPrice: product.price,
                    picture: product.mainPictureId // TODO: TROCAR PARA FOTO COM A COR CORRETA.
                };
                addItemToCart(itemCart);
                navigate('/carrinho');
            } else {
                alert("Estoque não disponível")
            }

        } else {
            setOpenAlert(true)
        }
    }

    const handleChangecolor = (newColorId: number) => {
        if (newColorId !== colorId) {
            setColorId(newColorId);
            setSizeId(undefined);
        }
    }

    useEffect(() => {
        api.get(`/v1/products/${productNameId}`)
            .then((res) => {
                setProduct(res.data);
                setColorId(res.data.mainPictureColorId);
                setCurPictureId(res.data.mainPictureId);
            }).catch((e) => {
                console.log(e);
                alert('Houve um erro, tente mais tarde.')
            });
    }, [])

    return (
        <Layout>
            <Dialog
                open={openAlert}
                onClose={() => setOpenAlert(false)}
                aria-labelledby="alert-dialog-title"
                aria-describedby="alert-dialog-description"
                fullWidth
                maxWidth='sm'
            >
                <DialogTitle id="alert-dialog-title">
                    {"Por favor, escolha um tamanho"}
                </DialogTitle>
                <DialogContent>
                    <Box sx={{ display: 'flex', justifyContent: 'center' }}>
                        {product && colorId &&
                            <SelectSize
                                selectedSizeId={sizeId}
                                onSelectSize={setSizeId}
                                selectedColorId={colorId}
                                gender={product.gender}
                            />
                        }
                    </Box>
                </DialogContent>
                <DialogActions>
                    <Button onClick={() => setOpenAlert(false)}>Cancelar</Button>
                    <div style={{ flex: '1 0 0' }} />
                    <Button onClick={handleBuy} variant="contained">Adicionar à sacola</Button>
                </DialogActions>
            </Dialog>
            <Container sx={{ padding: '0px !important' }}>
                <Grid container mt={isLargeScreen ? 4 : 0}>
                    <Grid item xs={12} lg={6} sx={{ display: 'flex', flexDirection: 'row', justifyContent: "center" }}>
                        {isLargeScreen && product &&
                            <Box width={120} mr={1} height={550} sx={{ overflow: 'auto'}}>
                                <img
                                    width={90}
                                    style={{ opacity: product.mainPictureId === curPictureId ? '1' : '0.4' }}
                                    src={URL_BACK + "/" + product.mainPictureId}
                                    onClick={() => setCurPictureId(product.mainPictureId)}
                                />
                                {product.pictures?.map((pic) => (
                                    <img
                                        key={pic.pictureId}
                                        style={{ opacity: pic.pictureId === curPictureId ? '1' : '0.4' }}
                                        width={90}
                                        src={URL_BACK + "/" + pic.pictureId}
                                        onClick={() => setCurPictureId(pic.pictureId)}
                                    />
                                ))}
                            </Box>
                        }
                        <Box width={502}>
                            <img
                                width={isLargeScreen ? '95%' : '100%'}
                                style={{ objectFit: 'contain', marginTop: 0, paddingTop: 0 }}
                                src={URL_BACK + "/" + curPictureId}
                            />
                        </Box>
                    </Grid>
                    <Grid item xs={12} lg={6}>
                        <Typography variant="h6">{product?.name}</Typography>
                        {product?.oldPrice && <Typography variant="subtitle1" color={'lightgrey'} sx={{ textDecoration: 'line-through' }}>De {formatMoney(product.oldPrice)}</Typography>}
                        {product?.price && <Typography variant="h5">{formatMoney(product.price)}</Typography>}

                        <Typography component="div" mt={2} sx={{ display: 'flex', flexDirection: 'row' }}>
                            <Box sx={{ fontWeight: 'bold', mr: 1 }}>Cor:</Box>
                            <Box sx={{ fontWeight: 'light' }}>{stocks.find((s) => s.colorId === colorId)?.colorName}</Box>
                        </Typography>

                        {product &&
                            <ColorBullets
                                selectedColorId={colorId}
                                onSelectColor={handleChangecolor}
                                gender={product.gender}
                            />
                        }
                        {product && colorId &&
                            <SelectSize
                                selectedSizeId={sizeId}
                                onSelectSize={setSizeId}
                                selectedColorId={colorId}
                                gender={product.gender}
                            />
                        }
                        <Box mt={4}>
                            <CustomButton title="ADICIONAR À SACOLA" onClick={handleBuy} width={isLargeScreen ? "70%" : '100%'} />
                        </Box>
                        <Box mt={4} p={isLargeScreen ? 0 : 2}>
                            <ButtonInput
                                value={cep}
                                onChange={setCep}
                                onClick={() => console.log('TODO')}
                                mask={formatCep}
                                label='CALCULAR FRETE'
                                buttonLabel='Calcular'
                                width={isLargeScreen ? '50%' : '100%'}
                            />
                        </Box>
                    </Grid>
                </Grid>
                <Grid container mt={4}>
                    <Typography>{product?.description}</Typography>
                    <Typography>Lorem, ipsum dolor sit amet consectetur adipisicing elit. Hic molestias accusantium fuga voluptas veniam laborum, unde dignissimos nobis cumque perferendis. Magnam vero, sapiente placeat aperiam recusandae ut aspernatur quo deleniti?Lorem ipsum dolor sit amet consectetur, adipisicing elit. Ullam beatae aliquam delectus natus totam ea commodi mollitia dolores aperiam placeat voluptates illum, libero itaque tenetur ut minus, aspernatur animi similique Lorem ipsum dolor sit amet consectetur, adipisicing elit. Earum, hic consequatur non ullam neque obcaecati similique eaque quidem in facere veritatis officia vitae iure officiis maxime quasi amet, fugit asperiores!</Typography>
                    <Typography>Lorem, ipsum dolor sit amet consectetur adipisicing elit. Hic molestias accusantium fuga voluptas veniam laborum, unde dignissimos nobis cumque perferendis. Magnam vero, sapiente placeat aperiam recusandae ut aspernatur quo deleniti?Lorem ipsum dolor sit amet consectetur, adipisicing elit. Ullam beatae aliquam delectus natus totam ea commodi mollitia dolores aperiam placeat voluptates illum, libero itaque tenetur ut minus, aspernatur animi similique Lorem ipsum dolor sit amet consectetur, adipisicing elit. Earum, hic consequatur non ullam neque obcaecati similique eaque quidem in facere veritatis officia vitae iure officiis maxime quasi amet, fugit asperiores!</Typography>
                    <Typography>Lorem, ipsum dolor sit amet consectetur adipisicing elit. Hic molestias accusantium fuga voluptas veniam laborum, unde dignissimos nobis cumque perferendis. Magnam vero, sapiente placeat aperiam recusandae ut aspernatur quo deleniti?Lorem ipsum dolor sit amet consectetur, adipisicing elit. Ullam beatae aliquam delectus natus totam ea commodi mollitia dolores aperiam placeat voluptates illum, libero itaque tenetur ut minus, aspernatur animi similique Lorem ipsum dolor sit amet consectetur, adipisicing elit. Earum, hic consequatur non ullam neque obcaecati similique eaque quidem in facere veritatis officia vitae iure officiis maxime quasi amet, fugit asperiores!</Typography>
                    <Typography>Lorem, ipsum dolor sit amet consectetur adipisicing elit. Hic molestias accusantium fuga voluptas veniam laborum, unde dignissimos nobis cumque perferendis. Magnam vero, sapiente placeat aperiam recusandae ut aspernatur quo deleniti?Lorem ipsum dolor sit amet consectetur, adipisicing elit. Ullam beatae aliquam delectus natus totam ea commodi mollitia dolores aperiam placeat voluptates illum, libero itaque tenetur ut minus, aspernatur animi similique Lorem ipsum dolor sit amet consectetur, adipisicing elit. Earum, hic consequatur non ullam neque obcaecati similique eaque quidem in facere veritatis officia vitae iure officiis maxime quasi amet, fugit asperiores!</Typography>
                </Grid>
            </Container>
        </Layout>
    );
}
